            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/vendors"]""",
            Tags = """["vendors","walkthrough","procurement"]""",
            ContentJson = """{"appRoute":"/vendors","startButtonLabel":"Tour Vendors","steps":[{"element":"[data-testid='new-vendor-btn']","popover":{"title":"Add Vendor Button","description":"Click here to create a new vendor. The dialog that opens has two sections: a main panel for contact details (company name, contact person, email, phone, notes) and a sidebar for address and settings (payment terms, active status).","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Vendors","description":"Search vendors by company name, contact name, email, or phone number. Type your search term and press Enter to filter the list. Results update based on matching text across all searchable fields.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Status Filter","description":"Filter vendors by active status: All (show everything), Active (currently doing business with), or Inactive (deactivated vendors). Inactive vendors are preserved for history but won't appear in PO vendor dropdowns.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Vendors Table","description":"The table shows all vendors matching your current filters. Columns include Company Name, Contact, Email, Phone, Active status (green/gray chip), PO count, and Created date. Click any column header to sort. Click any row to open the vendor detail dialog.","side":"top"}},{"element":"app-data-table thead th:nth-child(6)","popover":{"title":"PO Count Column","description":"Shows how many purchase orders have been placed with each vendor. This gives you a quick sense of how frequently you order from a supplier without opening the detail view.","side":"bottom"}}]}"""
