            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/vendors"]""",
            Tags = """["vendors","reference","procurement"]""",
            ContentJson = """{"title":"Vendors Field Reference","groups":[{"heading":"Vendor Form Fields — Contact Section","items":[{"label":"Company Name (required)","value":"Text input. The legal or trade name of the vendor. Must not be empty. This is the primary identifier shown in tables, dropdowns, and PO headers. data-testid: vendor-company"},{"label":"Contact Name","value":"Text input, optional. The primary contact person at the vendor company. Displayed beneath the company name in the detail header. data-testid: vendor-contact"},{"label":"Email","value":"Text input with email validation, optional. The vendor's primary email address. Must be a valid email format if provided. data-testid: vendor-email"},{"label":"Phone","value":"Text input, optional. The vendor's primary phone number. data-testid: vendor-phone"},{"label":"Notes","value":"Textarea (3 rows), optional. Free-form notes about the vendor — special instructions, account numbers, or relationship details. data-testid: vendor-notes"}]},{"heading":"Vendor Form Fields — Address Section (sidebar)","items":[{"label":"Address Line 1","value":"Text input, optional. Street address of the vendor."},{"label":"City","value":"Text input, optional. City name."},{"label":"State","value":"Dropdown of US states, optional. Two-letter state code."},{"label":"ZIP Code","value":"Text input with ZIP format mask, optional. 5-digit or 9-digit (XXXXX or XXXXX-XXXX)."},{"label":"Country","value":"Text input, optional. Country name or code. Defaults to US context."}]},{"heading":"Vendor Form Fields — Settings Section (sidebar)","items":[{"label":"Payment Terms","value":"Dropdown: Due on Receipt, Net 10, Net 15, Net 30, Net 45, Net 60, Net 90, 2/10 Net 30. Determines default payment expectations for POs placed with this vendor. data-testid: vendor-terms"},{"label":"Active (toggle, edit only)","value":"Slide toggle. Controls whether the vendor appears in active vendor lists and PO vendor dropdowns. Only shown when editing an existing vendor — new vendors default to Active."}]},{"heading":"Table Columns","items":[{"label":"Company Name","value":"Sortable. The vendor's company name, displayed in bold."},{"label":"Contact","value":"Sortable. Primary contact person name. Shows dash (—) when empty."},{"label":"Email","value":"Sortable. Contact email. Shows dash (—) when empty."},{"label":"Phone","value":"Sortable. Contact phone number. Shows dash (—) when empty."},{"label":"Active","value":"Sortable, filterable (enum). Green 'Active' chip or gray 'Inactive' chip. Width: 80px."},{"label":"POs","value":"Sortable, center-aligned. Count of purchase orders linked to this vendor. Width: 70px."},{"label":"Created","value":"Sortable, date type. Date the vendor was first created. Format: MM/dd/yyyy. Width: 110px."}]},{"heading":"Detail Dialog — Info Tab","items":[{"label":"Status","value":"Active (green chip) or Inactive (gray chip). Shows current vendor status."},{"label":"Email","value":"Displayed when present. The vendor's email address."},{"label":"Phone","value":"Displayed when present. The vendor's phone number."},{"label":"Payment Terms","value":"Displayed when set. The vendor's negotiated payment terms."},{"label":"Address","value":"Displayed when any address field is set. Shows street, city/state/ZIP, and country on separate lines."},{"label":"Notes","value":"Displayed when present. Free-form notes about the vendor."},{"label":"Accounting — External ID","value":"Displayed only when an accounting provider (e.g., QuickBooks) has synced this vendor. Shows the external system's ID for cross-reference."},{"label":"Created / Updated","value":"Timestamps showing when the vendor was first created and last modified. Format: MM/dd/yyyy."},{"label":"Activity Log","value":"Chronological activity feed showing all changes to the vendor record."}]},{"heading":"Detail Dialog — Purchase Orders Tab","items":[{"label":"PO Number","value":"The purchase order number. Clickable to open the PO detail dialog."},{"label":"Status","value":"Color-coded chip showing PO status (Draft, Sent, Partially Received, Received, Cancelled)."},{"label":"Expected Delivery Date","value":"When the order is expected to arrive. Format: MM/dd/yyyy."},{"label":"Created","value":"When the PO was created. Format: MM/dd/yyyy."},{"label":"Empty state","value":"When no POs exist for this vendor, shows 'No purchase orders' with receipt icon."}]},{"heading":"Detail Dialog — Scorecard Tab","items":[{"label":"Overall Grade","value":"Letter grade A through F displayed as a colored chip: A = success (green), B = success, C = warning (yellow), D = warning, F = error (red)."},{"label":"Overall Score","value":"Numeric score out of 100, shown beside the grade."},{"label":"Evaluation Period","value":"Date range the scorecard covers (start — end)."},{"label":"On-Time Delivery (40% weight)","value":"KPI chip showing percentage of deliveries received on or before the expected date. Detail rows: Total POs, Lines Received, On-Time %, Late Deliveries count."},{"label":"Quality Acceptance (30% weight)","value":"KPI chip showing acceptance rate. Detail rows: Inspected count, Rejected count, NCRs (non-conformance reports), Acceptance Rate %."},{"label":"Price (20% weight)","value":"Detail rows: Total Spend (currency), Average Price Variance %."},{"label":"Quantity Accuracy (10% weight)","value":"KPI chip showing how accurately the vendor ships the ordered quantities. Detail row: Qty Accuracy %."},{"label":"Total Spend","value":"KPI chip showing the total dollar amount spent with this vendor during the evaluation period."}]},{"heading":"Buttons and Actions","items":[{"label":"New Vendor (primary button)","value":"Opens the vendor creation dialog. Located in the page header. data-testid: new-vendor-btn"},{"label":"Save / Create Vendor (dialog)","value":"Creates a new vendor or saves changes to an existing one. Disabled when form is invalid or save is in progress. Shows validation popover on hover when form has errors. data-testid: vendor-save-btn"},{"label":"Cancel (dialog)","value":"Closes the dialog without saving changes. If the form has unsaved changes, a confirmation prompt appears."},{"label":"Edit (detail dialog)","value":"Icon button (pencil) in the detail header. Opens the edit dialog pre-filled with the vendor's current values."},{"label":"Close (detail dialog)","value":"Icon button (X) in the detail header. Closes the detail dialog and returns to the vendor list."},{"label":"Activate / Deactivate (detail dialog)","value":"Toggle button at the bottom of the Info tab. Switches the vendor between Active and Inactive status. Inactive vendors are preserved but hidden from active vendor lists."},{"label":"Delete (detail dialog)","value":"Danger button at the bottom of the Info tab. Soft-deletes the vendor (sets DeletedAt timestamp). The record is preserved but no longer visible."},{"label":"Row click","value":"Clicking any row in the vendors table opens the vendor detail dialog showing Info, Purchase Orders, and Scorecard tabs."}]},{"heading":"Validation Rules","items":[{"label":"Company Name","value":"Required. Cannot be empty. The only mandatory field on the vendor form."},{"label":"Email","value":"Optional, but if provided must be a valid email format (e.g., user@domain.com)."},{"label":"All other fields","value":"Optional. No length or format restrictions beyond standard input limits."},{"label":"Submit button popover","value":"When the form is invalid, hovering over the Save button shows a validation popover listing which fields need attention."}]},{"heading":"Accounting Integration Boundary","items":[{"label":"Standalone mode (no provider)","value":"Full vendor CRUD — create, edit, delete, activate/deactivate. All fields are editable."},{"label":"Integrated mode (QB connected)","value":"Vendor management becomes read-only in QB Engineer. Vendor records sync from QuickBooks. Edits must be made in the accounting system. The vendor list still displays, and PO history / scorecard remain fully functional."},{"label":"External ID / External Ref","value":"Populated automatically when a vendor is synced from an accounting provider. Shows the provider's internal ID for cross-reference. Not user-editable."},{"label":"Provider field","value":"Indicates which accounting system the vendor synced from (e.g., 'QuickBooks'). Not displayed in the UI but used internally for sync logic."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
